import{_ as a,y as g,a as u,o as e,ag as i,D as h,g as t,I as o}from"./chunks/framework.RVu0gECZ.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"authentication/2fa-authentication.md","filePath":"authentication/2fa-authentication.md","lastUpdated":1775725240000}'),r={name:"authentication/2fa-authentication.md"};function p(s,n,m,b,d,l){const c=g("ImagePopup");return e(),u("div",null,[n[0]||(n[0]=i('<p>Xác thực yếu tố # 2 (2FA)</p><p>Để giúp tài khoản quản trị viên an toàn hơn, chúng tôi đã thêm Xác thực hai yếu tố (2FA) vào VNS.</p><p>Tính năng này cung cấp mức độ bảo mật bổ sung bằng cách yêu cầu quản trị viên xác nhận danh tính của họ bằng bước thứ hai khi họ đăng nhập.</p><h3 id="cac-buoc-xac-thuc-2-yeu-to-2fa" tabindex="-1">Các bước xác thực 2 yếu tố (2FA) <a class="header-anchor" href="#cac-buoc-xac-thuc-2-yeu-to-2fa" aria-label="Permalink to &quot;Các bước xác thực 2 yếu tố (2FA)&quot;">​</a></h3><p><strong>Bước-1</strong> Trước tiên, bạn cần đăng nhập vào bảng quản trị VNS bằng thông tin đăng nhập (tên người dùng và mật khẩu). Sau khi đăng nhập, bạn sẽ được chuyển hướng đến bảng điều khiển.</p><p>Trên bảng điều khiển, bạn sẽ tìm thấy phần tài khoản của mình ở góc trên bên phải. Từ đó, bạn có thể truy cập chi tiết tài khoản của mình hoặc đăng xuất khỏi bảng quản trị. Nhấp vào nó và chọn <strong>Tài khoản của tôi</strong> để tiếp tục.</p><p>Để bạn tham khảo, một hình ảnh được cung cấp dưới đây.</p>',7)),h(c,{src:"/images/configure/account-login.png",alt:"Account Login"}),n[1]||(n[1]=t("p",null,[t("strong",null,"Bước-2"),o(" Tại đây, chi tiết tài khoản của bạn sẽ được hiển thị và bạn sẽ tìm thấy tùy chọn chuyển đổi để bật Xác thực hai yếu tố.")],-1)),h(c,{src:"/images/configure/enable-2fa.png",alt:"Account Login"}),n[2]||(n[2]=t("p",null,[t("strong",null,"Bước-3"),o(" Ngay sau khi bạn bật tính năng này, mã QR sẽ xuất hiện trên màn hình của bạn để thiết lập Xác thực hai yếu tố.")],-1)),h(c,{src:"/images/configure/qr-code.png",alt:"Account Login"}),n[3]||(n[3]=i("<p><strong>Bước-4</strong> Bây giờ, bạn cần cài đặt ứng dụng <strong>Google Authenticator</strong> trên điện thoại di động của mình. Nếu bạn là người dùng Android, hãy tải xuống từ Play Store và nếu bạn là người dùng iPhone, hãy tải xuống từ App Store.</p><p>Sau khi ứng dụng được cài đặt, hãy mở nó và hoàn tất đăng ký. Bạn sẽ tìm thấy biểu tượng <strong>“+”</strong> ở phía dưới cùng bên phải của ứng dụng—hãy nhấn vào biểu tượng đó và chọn tùy chọn quét mã QR.</p><p>Sau khi quét mã QR, mã xác minh sẽ được tạo trong ứng dụng. Nhập mã này vào trường <strong>Mã xác minh</strong> trên màn hình của bạn, sau đó nhấp vào nút <strong>Xác minh và bật</strong></p><p>Sau khi hoàn tất, Xác thực hai yếu tố của bạn sẽ được kích hoạt thành công.</p>",4))])}const k=a(r,[["render",p]]);export{_ as __pageData,k as default};
